import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { AttendanceService } from '../../../../core/services/attendance.service';
import { StaffService } from '../../../../core/services/staff.service';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-attendance-form',
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './attendance-form.component.html',
  styleUrl: './attendance-form.component.css',
})
export class AttendanceFormComponent implements OnInit {
  staffList: any[] = [];
  loading = false;
  errorMsg = '';

  attendanceForm!: FormGroup;

 

  constructor(
    private fb: FormBuilder,
    private attendanceService: AttendanceService,
    private staffService: StaffService,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    this.attendanceForm = this.fb.group({
    staffId: ['', Validators.required],
    month: ['', Validators.required],
    year: ['', Validators.required],
    presentDays: [0, [Validators.required, Validators.min(0)]],
    leaveDays: [0, [Validators.required, Validators.min(0)]],
    leaveReason: [''],
  });
  }

  ngOnInit(): void {
    this.loadStaff();

    const now = new Date();
    const defaults = {
      month: now.getMonth() + 1,
      year: now.getFullYear(),
    };

    this.attendanceForm.patchValue(defaults);

    const qp = this.route.snapshot.queryParamMap;
    const staffId = qp.get('staffId');
    const month = qp.get('month');
    const year = qp.get('year');
    const leaveDays = qp.get('leaveDays');
    const presentDays = qp.get('presentDays');

    this.attendanceForm.patchValue({
      ...(staffId ? { staffId: Number(staffId) } : {}),
      ...(month ? { month: Number(month) } : {}),
      ...(year ? { year: Number(year) } : {}),
      ...(leaveDays ? { leaveDays: Number(leaveDays) } : {}),
      ...(presentDays ? { presentDays: Number(presentDays) } : {}),
    });
  }

  loadStaff() {
    this.staffService.getStaff({ limit: 100 }).subscribe({
      next: (res) => {
        this.staffList = res.data.data;
      },
    });
  }

  onSubmit() {
    if (this.attendanceForm.invalid) {
      this.attendanceForm.markAllAsTouched();
      return;
    }

    this.loading = true;
    this.errorMsg = '';

    const raw = this.attendanceForm.value;
    const totalDays = this.getDaysInMonth(raw.year, raw.month);
    const payload = {
      ...raw,
      totalDays
    };

    this.attendanceService.createAttendance(payload).subscribe({
        next: () => {
          this.loading = false;
          this.attendanceForm.reset();
          this.router.navigate(['/attendance']);
        },
        error: (err: any) => {
          this.errorMsg = err?.error?.message || 'Failed to save attendance';
          this.loading = false;
        },
      });
  }

  private getDaysInMonth(year: number, month: number) {
    const y = Number(year);
    const m = Number(month);
    if (!y || !m || m < 1 || m > 12) return 30;
    return new Date(y, m, 0).getDate();
  }
}
